from docx import Document
from docx.shared import Pt
from docx.enum.text import WD_ALIGN_PARAGRAPH


TARGET = r"C:/Users/Danie/OneDrive/Desktop/turrrr/ПРАКТИЧЕСКАЯ_ЧАСТЬ_3_ПУНКТА.docx"


def add_heading(doc: Document, text: str, size: int = 14) -> None:
    p = doc.add_paragraph()
    p.alignment = WD_ALIGN_PARAGRAPH.LEFT
    r = p.add_run(text)
    r.bold = True
    r.font.name = "Times New Roman"
    r.font.size = Pt(size)


def add_text(doc: Document, text: str) -> None:
    p = doc.add_paragraph()
    p.alignment = WD_ALIGN_PARAGRAPH.JUSTIFY
    p.paragraph_format.first_line_indent = Pt(35)
    r = p.add_run(text)
    r.font.name = "Times New Roman"
    r.font.size = Pt(14)


doc = Document()

add_heading(doc, "1. Постановка задачи")
add_text(doc, "Цель разработки заключается в создании веб-приложения туристической платформы, объединяющего каталог туров, бронирование, пользовательские коммуникации и административные инструменты управления. На уровне прикладной постановки важно было не только реализовать отдельные функции, но и обеспечить их совместную работу в рамках единой ролевой модели: гость, зарегистрированный пользователь и администратор.")
add_text(doc, "Практическая задача проекта состояла в проектировании структуры данных и программных модулей так, чтобы система поддерживала реальную эксплуатацию: конкурентные обращения к данным, устойчивую обработку ошибок, отслеживание статусов и прозрачность пользовательских действий. Дополнительно учитывались требования к расширяемости, чтобы новые модули можно было добавлять без полной переработки базовой архитектуры.")

add_heading(doc, "2. Проектирование базы данных")
add_text(doc, "Проектирование базы данных выполнялось на основе ERD-подхода: сначала выделялись сущности предметной области, затем формировались атрибуты и связи между таблицами, после чего проверялась корректность модели на ключевых пользовательских сценариях. В качестве хранилища использовалась PostgreSQL (в составе Supabase), что позволило использовать строгую реляционную модель, внешние ключи, индексацию и удобную интеграцию с API-уровнем.")
add_text(doc, "На этапе проектирования применялся принцип разделения ответственности: каждая таблица должна описывать один устойчивый бизнес-объект. Это позволило исключить дублирование данных, упростить чтение структуры и обеспечить удобное сопровождение. Например, таблица бронирований хранит факт брони, а состав участников вынесен в отдельную таблицу; сессии поддержки отделены от сообщений, чтобы различать контекст обращения и его содержимое.")
add_text(doc, "На данном этапе в текст вставляется ERD-диаграмма как обобщенная визуальная схема проектируемой структуры данных.")
add_text(doc, "[МЕСТО ДЛЯ РИСУНКА ERD-ДИАГРАММЫ]")
add_text(doc, "Рисунок X — ERD-диаграмма базы данных разработанного приложения.")
add_text(doc, "Логика построения схемы начинается с таблицы profiles, которая выступает опорной точкой пользовательского контура: в ней хранятся профильные данные, роль и признаки ограничений. Роль используется для разграничения доступа в API, а признаки модерации позволяют централизованно управлять ограничениями. Именно от profiles строятся связи к таблицам бронирований, поддержки, сообщений и уведомлений, что обеспечивает целостную модель пользовательской активности.")
add_text(doc, "Географическая часть вынесена в справочник cities, а туристический каталог сосредоточен в tours. Такое разделение позволяет нормализовать данные и не дублировать названия локаций в каждой карточке. В tours хранятся бизнес-параметры тура: стоимость, статус и данные о вместимости. Поля max_participants и current_participants участвуют в проверках при бронировании и предотвращают переполнение группы. Поле status задает управляемый жизненный цикл публикации тура: это важно как для витрины, так и для административного управления.")
add_text(doc, "Транзакционный слой реализуется таблицей bookings, где фиксируется факт оформления заявки пользователем на конкретный тур. При проектировании было важно разделить статус самой брони и платежный статус, чтобы корректно обрабатывать промежуточные состояния процесса. Для детализации состава поездки отдельно используется booking_attendees: это позволяет хранить данные каждого участника в отдельных строках, а не перегружать запись бронирования повторяющимися полями. В результате структура остается гибкой и удобной для расширения.")
add_text(doc, "Коммуникационный контур построен через пару support_sessions и chat_messages. Таблица support_sessions хранит метаданные обращения: кто инициировал диалог, в каком состоянии находится запрос, когда сессия открыта и закрыта. Это дает операторам поддержку workflow-режима и позволяет управлять очередью обращений. Таблица chat_messages хранит уже содержимое переписки с привязкой к конкретной сессии, отправителю и статусу прочтения. Такая декомпозиция обеспечивает прозрачность истории диалога и ускоряет выборку активных чатов.")
add_text(doc, "Отдельным слоем обратной связи выступает notifications — таблица пользовательских уведомлений о событиях системы. Она объединяет сообщения из разных модулей в едином формате и используется для отображения счетчиков новых событий в интерфейсе. Поле is_read разделяет новые и просмотренные записи, а связь с profiles позволяет формировать персональную ленту уведомлений. Такой подход упрощает сопровождение и дает возможность в дальнейшем расширять каналы доставки без перестройки остальных бизнес-таблиц.")

add_heading(doc, "3. Проектирование пользовательского интерфейса")
add_text(doc, "Проектирование пользовательского интерфейса выполнялось с учетом ролевой структуры системы и приоритетных пользовательских сценариев. Для каждой роли сформирован собственный набор экранов и действий, что снизило визуальную перегрузку и повысило предсказуемость навигации.")
add_text(doc, "На уровне интерфейсной логики отдельно проработаны состояния загрузки, ошибки валидации, успешные операции и пустые выборки данных. Такой подход повышает удобство использования и снижает количество пользовательских ошибок при работе с функционалом платформы.")

